        if (protocol == null || !ALLOWED_PROTOCOLS.contains(protocol.toLowerCase())) {
            throw new URISyntaxException(imageUrl, "Invalid or unsupported protocol: " + protocol);
        }

        // Validate host exists
        String host = uri.getHost();
        if (host == null || host.isEmpty()) {
            throw new URISyntaxException(imageUrl, "Host is missing");
        }

        // Validate port (only allow standard HTTP/HTTPS ports)
