                System.err.println("Error: HTTP response code " + responseCode);
                return false;
            }

            validateContentType(connection.getContentType());

            try (InputStream inputStream = connection.getInputStream()) {
                BufferedImage image = ImageIO.read(inputStream);

                if (image != null) {
                    System.out.println("Image processed successfully: " + image.getWidth() + "x" + image.getHeight());
                    return true;
                } else {
                    System.err.println("Error: Could not read image from URL");
                    return false;
