            return false;
        } catch (UnknownHostException e) {
            System.err.println("Error: Unknown host - " + e.getMessage());
            return false;
        } catch (IOException e) {
            System.err.println("Error processing image from URL: " + e.getMessage());
            return false;
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
