        // IPv6: fc00::/7
        if (addr.isSiteLocalAddress()) {
            throw new SecurityException("Access to private network addresses is not allowed");
        }

        // Block wildcard address (0.0.0.0)
        if (addr.isAnyLocalAddress()) {
            throw new SecurityException("Access to wildcard addresses is not allowed");
        }
    }

    private HttpURLConnection createSecureConnection(URL url) throws IOException {
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();

        connection.setConnectTimeout(CONNECTION_TIMEOUT_MS);
        connection.setReadTimeout(READ_TIMEOUT_MS);
        connection.setInstanceFollowRedirects(false);
        connection.setRequestMethod("GET");
        connection.setRequestProperty("User-Agent", "ImageService/1.0");

        return connection;
    }

    private boolean isRedirectResponse(int responseCode) {
        return responseCode == HttpURLConnection.HTTP_MOVED_PERM || 
               responseCode == HttpURLConnection.HTTP_MOVED_TEMP ||
               responseCode == HttpURLConnection.HTTP_SEE_OTHER ||
               responseCode == 307 || 
               responseCode == 308;
    }

    private void validateContentType(String contentType) {
        if (contentType == null) {
            throw new SecurityException("Content-Type header is missing");
        }

        String normalizedContentType = contentType.toLowerCase().split(";")[0].trim();

        if (!ALLOWED_CONTENT_TYPES.contains(normalizedContentType)) {
            throw new SecurityException("Invalid content type: " + contentType + 
                ". Only image types are allowed.");
        }
    }
}

